import React from 'react';
import {StyleSheet, View, TextInput} from 'react-native';
import Animated, {useSharedValue, useAnimatedScrollHandler, useAnimatedStyle, interpolate, Extrapolation} from 'react-native-reanimated';
export function PullToSearch({children}: {children: React.ReactNode}) {
  const y = useSharedValue(0);
  const handler = useAnimatedScrollHandler({onScroll: e => { y.value = e.contentOffset.y; }});
  const searchStyle = useAnimatedStyle(() => ({height: interpolate(-y.value, [0, 60], [0, 44], Extrapolation.CLAMP), opacity: interpolate(-y.value, [10, 50], [0, 1], Extrapolation.CLAMP)}));
  return (<View style={{flex:1}}><Animated.View style={[s.search, searchStyle]}><TextInput placeholder='Search messages' placeholderTextColor='#8E8E93' style={s.input}/></Animated.View><Animated.ScrollView onScroll={handler} scrollEventThrottle={16} bounces>{children}</Animated.ScrollView></View>);
}
const s = StyleSheet.create({search:{overflow:'hidden', paddingHorizontal:12}, input:{flex:1, height:36, paddingHorizontal:14, backgroundColor:'#1C1C1E', borderRadius:10, color:'#fff'}});

