import React, {useEffect} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import {useSharedValue, withTiming, withDelay, useDerivedValue} from 'react-native-reanimated';
const LOGO_PATH = 'M40 20 L60 60 L20 60 Z';
export function LogoMark({size = 80}: {size?: number}) {
  const stroke = useSharedValue(0); const fill = useSharedValue(0);
  useEffect(() => { stroke.value = withTiming(1, {duration: 700}); fill.value = withDelay(700, withTiming(1, {duration: 400})); }, []);
  const strokeColor = useDerivedValue(() => `rgba(10,132,255,${stroke.value})`);
  const fillColor = useDerivedValue(() => `rgba(10,132,255,${fill.value * 0.5})`);
  return (<View style={{width: size, height: size}}><Canvas style={StyleSheet.absoluteFill}><Path path={LOGO_PATH} color={fillColor}/><Path path={LOGO_PATH} style='stroke' strokeWidth={3} color={strokeColor}/></Canvas></View>);
}

