// Gauge.tsx
import React, {useEffect} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia, Line, vec} from '@shopify/react-native-skia';
import {useSharedValue, withSpring, useDerivedValue} from 'react-native-reanimated';
export function Gauge({value, max = 100, size = 200}: {value: number; max?: number; size?: number}) {
  const v = useSharedValue(value/max);
  useEffect(() => { v.value = withSpring(value/max, {damping: 18, stiffness: 200}); }, [value]);
  const cx = size/2; const cy = size * 0.7; const r = size/2 - 12;
  const arcPath = Skia.Path.Make(); arcPath.addArc({x: cx-r, y: cy-r, width: r*2, height: r*2}, 180, 180);
  const needleEnd = useDerivedValue(() => { const angle = 180 + 180 * v.value; const rad = (angle * Math.PI) / 180; return vec(cx + Math.cos(rad) * r * 0.9, cy + Math.sin(rad) * r * 0.9); });
  return (<View style={{width: size, height: size * 0.8}}><Canvas style={StyleSheet.absoluteFill}><Path path={arcPath} style='stroke' strokeWidth={10} color='#2C2C2E'/><Line p1={vec(cx, cy)} p2={needleEnd} color='#FF453A' strokeWidth={3} strokeCap='round'/></Canvas></View>);
}

